import os,json,argparse,torch,torch.nn as nn

def load_pt(p):
    kw={'map_location':'cpu','weights_only':False}
    try:
        kw['mmap']=True
    except Exception:
        pass
    return torch.load(p,**kw)

def hist(v,k):
    v=v.long(); m=(v>=0)&(v<k)
    return torch.bincount(v[m],minlength=k).float()

def stats(v):
    v=v.float().view(-1)
    if v.numel()==0:
        return torch.zeros(4)
    return torch.tensor([v.mean(),v.std(unbiased=False),v.min(),v.max()])

def feat(x,ei,ea):
    x=x.long(); ea=ea.long(); n=x.size(0); e=ea.size(0)
    out=[torch.tensor([float(n),float(e),float(e)/max(float(n),1.0),float(e)/max(float(n*n),1.0)])]
    indeg=torch.bincount(ei[0].long(),minlength=n).float() if ei.numel() else torch.zeros(n)
    outdeg=torch.bincount(ei[1].long(),minlength=n).float() if ei.numel() else torch.zeros(n)
    out += [stats(indeg), stats(outdeg), stats(indeg-outdeg), stats(indeg+outdeg)]
    ks=[119,5,12,12,10,6,8,2,2]
    for j,k in enumerate(ks):
        col=x[:,j]
        out += [hist(col,k), stats(col)]
    eks=[6,6,2]
    for j,k in enumerate(eks):
        col=ea[:,j] if e else torch.zeros(0,dtype=torch.long)
        out += [hist(col,k), stats(col)]
    if n:
        out += [stats((x[:,0]>0).float()), stats((x[:,7]>0).float()), stats((x[:,8]>0).float())]
        out += [stats((x[:,3]!=5).float()), stats((x[:,4]>0).float()), stats((x[:,5]>0).float())]
    else:
        out += [torch.zeros(4) for _ in range(6)]
    if e:
        out += [stats((ea[:,0]>0).float()), stats((ea[:,1]>0).float()), stats((ea[:,2]>0).float())]
    else:
        out += [torch.zeros(4) for _ in range(3)]
    return torch.cat([t.view(-1) for t in out]).float()

def main():
    ap=argparse.ArgumentParser()
    ap.add_argument('--data_path',required=True)
    ap.add_argument('--checkpoint',required=True)
    ap.add_argument('--output',required=True)
    args=ap.parse_args()
    ck=torch.load(args.checkpoint,map_location='cpu',weights_only=False)
    d=ck.get('drop',0.0)
    model=nn.Sequential(
        nn.Linear(ck['in_dim'],ck['hidden']),nn.ReLU(),nn.Dropout(d),
        nn.Linear(ck['hidden'],ck['hidden']),nn.ReLU(),nn.Dropout(d),
        nn.Linear(ck['hidden'],128)
    )
    model.load_state_dict(ck['state_dict']); model.eval(); mu=ck['mu']; sd=ck['sd']
    obj=load_pt(os.path.join(args.data_path,'test.pt')); preds=[]
    with torch.no_grad():
        for x,ei,ea in zip(obj['node_features'],obj['edge_index'],obj['edge_attr']):
            z=(feat(x,ei,ea).view(1,-1)-mu)/sd
            p=torch.sigmoid(model(z))[0].tolist()
            preds.append([float(v) for v in p])
    with open(args.output,'w') as f:
        json.dump({'predictions':preds},f)

if __name__=='__main__':
    main()
